import React from "react";

const HEARTS = ["💖", "💕", "🩷", "💗", "💓", "💞", "❤️", "🌹", "💘", "💝"];

// Generate semua data hati SEKALI di luar component supaya tidak re-generate saat re-render

const IMGS = {
  dinner: "data:image/jpeg;base64,",
  streetfood: "data:image/jpeg;base64,",
  apd: "data:image/jpeg;base64,",
  shopping: "data:image/jpeg;base64,",
  eskrim: "data:image/jpeg;base64,",
  tembak: "data:image/jpeg;base64,",
};

const HEART_DATA = [...Array(30)].map((_, i) => ({
  id: i,
  symbol: HEARTS[Math.floor(Math.random() * HEARTS.length)],
  left: Math.random() * 96 + 2,           // 2% ~ 98% — menyebar penuh kiri ke kanan
  size: 12 + Math.random() * 20,
  duration: 5 + Math.random() * 7,
  delay: Math.random() * 8,
  rotate: Math.random() > 0.5 ? -(8 + Math.random() * 18) : (8 + Math.random() * 18),
}));

function FloatingHearts() {
  return (
    <>
      <style>{`
        @keyframes heartFloat {
          0%   { transform: translateY(0px) rotate(0deg); opacity: 0; }
          8%   { opacity: 1; }
          85%  { opacity: 0.7; }
          100% { transform: translateY(-105vh) rotate(var(--rot)); opacity: 0; }
        }
        @keyframes pulse {
          0%, 100% { transform: scale(1); }
          50% { transform: scale(1.1); }
        }
        @keyframes shimmer {
          0%, 100% { opacity: 0.7; }
          50% { opacity: 1; }
        }
        html, body {
          overflow: hidden !important;
          height: 100% !important;
          max-height: 100vh !important;
        }
      `}</style>

      <div
        style={{
          position: "fixed",
          inset: 0,
          overflow: "hidden",
          pointerEvents: "none",
          zIndex: 0,
        }}
      >
        {HEART_DATA.map((h) => (
          <div
            key={h.id}
            style={{
              position: "absolute",
              left: `${h.left}%`,
              bottom: "-30px",
              fontSize: `${h.size}px`,
              "--rot": `${h.rotate}deg`,
              animation: `heartFloat ${h.duration}s linear ${h.delay}s infinite`,
              opacity: 0,
              filter: "drop-shadow(0 0 4px rgba(255,80,130,0.55))",
              userSelect: "none",
            }}
          >
            {h.symbol}
          </div>
        ))}
      </div>
    </>
  );
}

export default function CuteDateInvite() {
  const [page, setPage] = React.useState(0);
  const [noPos, setNoPos] = React.useState({ x: 0, y: 0 });
  const [yesScale, setYesScale] = React.useState(1);
  const [dateTime, setDateTime] = React.useState("");
  const [selectedPlans, setSelectedPlans] = React.useState([]);
  const [nightPlan, setNightPlan] = React.useState("");

  // Lock scroll secara paksa saat component mount
  React.useEffect(() => {
    document.documentElement.style.overflow = "hidden";
    document.body.style.overflow = "hidden";
    document.body.style.height = "100vh";
    return () => {
      document.documentElement.style.overflow = "";
      document.body.style.overflow = "";
      document.body.style.height = "";
    };
  }, []);

  const allPlans = [
    { label: "🛍️ Shopping", img: IMGS.shopping },
    { label: "🎮 Main arcade", img: IMGS.tembak },
    { label: "🍰 Dessert date", img: IMGS.eskrim },
  ];

  const moveNoButton = () => {
    setNoPos({
      x: Math.random() * 140 - 70,
      y: Math.random() * 80 - 40,
    });
    setYesScale((prev) => prev + 0.06);
  };

  return (
    <div
      style={{
        width: "100vw",
        height: "100vh",
        overflow: "hidden",
        background: "linear-gradient(135deg, #fbcfe8 0%, #fce7f3 50%, #fda4af 100%)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        position: "fixed",
        inset: 0,
        fontFamily: "sans-serif",
      }}
    >
      <audio id="bgm" loop>
        <source src="/music.mp3" type="audio/mpeg" />
      </audio>

      {/* FLOATING HEARTS — semua page */}
      <FloatingHearts />

      {/* MAIN CARD */}
      <div
        style={{
          background: "rgba(255,255,255,0.82)",
          backdropFilter: "blur(12px)",
          borderRadius: "22px",
          padding: "16px",
          width: "min(92vw, 640px)",
          height: "min(68vh, 520px)",
          textAlign: "center",
          position: "relative",
          zIndex: 10,
          border: "1px solid #fecdd3",
          boxShadow: "0 20px 60px rgba(244,63,94,0.15)",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          overflow: "hidden",
        }}
      >

        {/* PAGE 1 */}
        {page === 0 && (
          <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: "6px", width: "100%" }}>
            <div style={{ fontSize: "32px", animation: "pulse 1.6s ease-in-out infinite" }}>💌</div>
            <h1 style={{ fontSize: "clamp(18px,4vw,26px)", fontWeight: 700, color: "#f43f5e", margin: 0 }}>
              Wanna go out with me?
            </h1>
            <p style={{ color: "#6b7280", fontSize: "12px", margin: 0 }}>i already planned a cute day for us 😋</p>

            <div style={{ position: "relative", height: "90px", display: "flex", alignItems: "center", justifyContent: "center", width: "100%" }}>
              {/* YES */}
              <button
                onClick={() => {
                  setPage(1);
                  const audio = document.getElementById("bgm");
                  if (audio) { audio.currentTime = 0; audio.play().catch(() => {}); }
                }}
                style={{
                  transform: `scale(${yesScale})`,
                  background: "#f43f5e",
                  color: "white",
                  border: "none",
                  padding: "6px 20px",
                  borderRadius: "999px",
                  fontSize: "13px",
                  fontWeight: 600,
                  cursor: "pointer",
                  boxShadow: "0 4px 20px rgba(244,63,94,0.4)",
                  position: "relative",
                  zIndex: 10,
                  transition: "transform 0.2s",
                }}
              >
                YES 💖
              </button>

              {/* NO — posisi absolut di dalam container yg cukup tinggi */}
              <button
                onMouseEnter={moveNoButton}
                onClick={moveNoButton}
                style={{
                  transform: `translate(calc(-50% + ${noPos.x}px), ${noPos.y}px)`,
                  background: "#f3f4f6",
                  border: "none",
                  padding: "6px 20px",
                  borderRadius: "999px",
                  fontSize: "13px",
                  fontWeight: 600,
                  cursor: "pointer",
                  position: "absolute",
                  left: "calc(50% + 70px)",
                  top: "50%",
                  marginTop: "-16px",
                  transition: "transform 0.18s cubic-bezier(.17,.67,.35,1.4)",
                  zIndex: 9,
                  whiteSpace: "nowrap",
                }}
              >
                no 🙄
              </button>
            </div>

            {yesScale > 1 && (
              <p style={{ fontSize: "10px", color: "#9ca3af", margin: 0 }}>
                {yesScale > 1.3 ? "tombol no nya eror parah wkwk 😭" : "kenapa tombolnya rusak ya 🤨"}
              </p>
            )}
          </div>
        )}

        {/* PAGE 2 */}
        {page === 1 && (
          <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: "8px", width: "100%" }}>
            <div style={{ fontSize: "32px", animation: "pulse 1.6s ease-in-out infinite" }}>📅</div>
            <h1 style={{ fontSize: "20px", fontWeight: 700, color: "#f43f5e", margin: 0 }}>kapan aku jemput? 💕</h1>
            <p style={{ color: "#6b7280", fontSize: "12px", margin: 0 }}>pilih tanggal + jam 😋</p>

            <div style={{ background: "#fff0f3", padding: "12px", borderRadius: "16px", border: "1px solid #fecdd3", width: "100%", maxWidth: "280px" }}>
              <input
                type="datetime-local"
                value={dateTime}
                onChange={(e) => setDateTime(e.target.value)}
                style={{ width: "100%", padding: "8px", borderRadius: "10px", fontSize: "12px", border: "1px solid #fecdd3", outline: "none", boxSizing: "border-box" }}
              />
              <button
                disabled={!dateTime}
                onClick={() => setPage(2)}
                style={{
                  marginTop: "8px",
                  width: "100%",
                  padding: "8px",
                  borderRadius: "10px",
                  fontSize: "12px",
                  fontWeight: 600,
                  border: "none",
                  cursor: dateTime ? "pointer" : "not-allowed",
                  background: dateTime ? "#f43f5e" : "#e5e7eb",
                  color: dateTime ? "white" : "#9ca3af",
                  transition: "all 0.2s",
                }}
              >
                continue 💌
              </button>
            </div>
          </div>
        )}

        {/* PAGE 3 */}
        {page === 2 && (
          <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: "8px", width: "100%" }}>
            <div style={{ fontSize: "28px", animation: "shimmer 1.8s ease-in-out infinite" }}>💌</div>
            <h1 style={{ fontSize: "20px", fontWeight: 700, color: "#f43f5e", margin: 0 }}>date agenda</h1>

            <div style={{ background: "#fff0f3", borderRadius: "14px", padding: "10px", textAlign: "left", fontSize: "12px", width: "100%", maxWidth: "360px" }}>
              <p style={{ margin: "2px 0" }}>1. makan lucu dulu 🍜</p>
              <p style={{ margin: "2px 0" }}>2. ngobrol lucu 🎀</p>
              <p style={{ margin: "2px 0" }}>{selectedPlans.length + 3}. pilih lagi 😋</p>
            </div>

            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: "6px", width: "100%", maxWidth: "360px" }}>
              {allPlans.filter((item) => !selectedPlans.map(p=>p.label||p).includes(item.label)).map((item) => (
                <button
                  key={item}
                  onClick={() => {
                    const updated = [...selectedPlans, item.label];
                    setSelectedPlans(updated);
                    if (updated.length === allPlans.length) setPage(3);
                  }}
                  style={{ background: "#fecdd3", border: "none", padding: "0", borderRadius: "12px", fontSize: "12px", fontWeight: 500, cursor: "pointer", overflow: "hidden", display: "flex", flexDirection: "column" }}
                >
                  <img src={item.img} alt={item.label} style={{ width: "100%", height: "70px", objectFit: "cover" }} />
                  <span style={{ padding: "6px 8px", display: "block" }}>{item.label}</span>
                </button>
              ))}
            </div>
          </div>
        )}

        {/* PAGE 4 */}
        {page === 3 && (
          <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: "8px", width: "100%" }}>
            <div style={{ fontSize: "32px", animation: "pulse 1.4s ease-in-out infinite" }}>🌙</div>
            <h1 style={{ fontSize: "20px", fontWeight: 700, color: "#f43f5e", margin: 0 }}>Special night ✨</h1>
            <p style={{ color: "#6b7280", fontSize: "12px", margin: 0 }}>pilih malemnya 😋</p>

            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: "6px", width: "100%", maxWidth: "360px" }}>
              {[
                { label: "APD painting 🎨", img: IMGS.apd },
                { label: "Street food 🌃", img: IMGS.streetfood },
                { label: "Dinner 🍽️", img: IMGS.dinner },
              ].map((opt) => (
                <button key={opt.label} onClick={() => { setNightPlan(opt.label); setPage(4); }}
                  style={{ background: "#fce7f3", border: "none", padding: "0", borderRadius: "12px", fontSize: "11px", cursor: "pointer", overflow: "hidden", display: "flex", flexDirection: "column" }}>
                  <img src={opt.img} alt={opt.label} style={{ width: "100%", height: "70px", objectFit: "cover" }} />
                  <span style={{ padding: "5px 4px", display: "block" }}>{opt.label}</span>
                </button>
              ))}
            </div>
          </div>
        )}

        {/* FINAL */}
        {page === 4 && (
          <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: "8px", width: "100%" }}>
            <div style={{ fontSize: "36px", animation: "pulse 1.2s ease-in-out infinite" }}>💖</div>
            <h1 style={{ fontSize: "22px", fontWeight: 700, color: "#f43f5e", margin: 0 }}>It's a date then.</h1>

            <div style={{ background: "#fff0f3", borderRadius: "14px", padding: "10px", textAlign: "left", fontSize: "12px", width: "100%", maxWidth: "360px" }}>
              <p style={{ margin: "3px 0" }}>📅 <b>Date:</b> {new Date(dateTime).toLocaleString()}</p>
              <p style={{ margin: "3px 0" }}>🎀 <b>Activities:</b> {["makan lucu dulu 🍜", "ngobrol lucu 🎀", ...selectedPlans].join(" → ")}</p>
              <p style={{ margin: "3px 0" }}>🌙 <b>Night:</b> {nightPlan}</p>
              <p style={{ margin: "3px 0" }}>👗 <b>Dresscode:</b> whatever you feel comfortable in — you already look great regardless.</p>
            </div>

            <div style={{ background: "white", borderRadius: "12px", padding: "10px", border: "1px solid #fecdd3", width: "100%", maxWidth: "320px" }}>
              <p style={{ fontStyle: "italic", color: "#6b7280", fontSize: "12px", margin: 0 }}>"still choosing you, always."</p>
            </div>

            <button
              onClick={() => {
                setPage(0); setYesScale(1); setNoPos({ x: 0, y: 0 });
                setDateTime(""); setSelectedPlans([]); setNightPlan("");
              }}
              style={{ background: "#f43f5e", color: "white", border: "none", padding: "6px 20px", borderRadius: "999px", fontSize: "12px", fontWeight: 600, cursor: "pointer" }}
            >
              replay 💞
            </button>
          </div>
        )}
      </div>
    </div>
  );
}